/**
 * Harness Configuration
 *
 * Defines all available harnesses in the MMS project.
 * Each harness has its own features.json and isolation rules.
 */

export interface HarnessConfig {
  id: string;
  name: string;
  icon: string;
  description: string;
  cwd: string;
  featuresPath: string;
  progressPath: string;
  isolationPrompt: string;
}

// Base path for the project
const PROJECT_ROOT = import.meta.dir.replace('/scripts', '');

/**
 * Root harness - apps/canvas
 */
const rootHarness: HarnessConfig = {
  id: 'root',
  name: 'Root (apps/canvas)',
  icon: '🏠',
  description: 'Main MMS application with semantic zoom',
  cwd: PROJECT_ROOT,
  featuresPath: `${PROJECT_ROOT}/features.json`,
  progressPath: `${PROJECT_ROOT}/claude-progress.txt`,
  isolationPrompt: `You are working on the MMS ROOT project (apps/canvas).

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🏠 ROOT SCOPE RULES - READ CAREFULLY
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

✅ YOU MAY MODIFY:
   - apps/canvas/**/* (the main MMS app)
   - packages/toolkit/**/* (shared utilities)
   - Root features.json, claude-progress.txt, CLAUDE.md
   - docs/**/* and agent_docs/**/*

❌ DO NOT MODIFY (these have their OWN harness):
   - packages/harness-orchestrator/**/*
   - packages/harness-dashboard/**/*

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📋 HARNESS PROTOCOL
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

1. READ claude-progress.txt → current state
2. READ features.json → find next feature (passes: false)
3. IMPLEMENT the feature
4. TEST visually with Playwright MCP
5. UPDATE features.json → set passes: true
6. UPDATE claude-progress.txt → add session notes
7. COMMIT changes

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
⚠️  When done with the current feature, type /exit to proceed to next.
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`,
};

/**
 * Harness Orchestrator package
 */
const orchestratorHarness: HarnessConfig = {
  id: 'harness-orchestrator',
  name: 'harness-orchestrator',
  icon: '📦',
  description: 'CLI tool for harness management',
  cwd: `${PROJECT_ROOT}/packages/harness-orchestrator`,
  featuresPath: `${PROJECT_ROOT}/packages/harness-orchestrator/features.json`,
  progressPath: `${PROJECT_ROOT}/packages/harness-orchestrator/progress.txt`,
  isolationPrompt: `You are working on the @mms/harness-orchestrator package.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🔒 ISOLATION RULES - READ CAREFULLY
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

✅ YOU MAY ONLY MODIFY:
   - packages/harness-orchestrator/**/*
   - This includes: src/, features.json, progress.txt, CLAUDE.md, package.json

❌ DO NOT MODIFY (these belong to the ROOT MMS project):
   - apps/canvas/**/*
   - Root features.json, claude-progress.txt, CLAUDE.md
   - packages/toolkit/**/*
   - Any files outside packages/harness-orchestrator/

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📋 PACKAGE HARNESS PROTOCOL
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

1. READ packages/harness-orchestrator/progress.txt → current state
2. READ packages/harness-orchestrator/features.json → find next feature
3. READ packages/harness-orchestrator/CLAUDE.md → package instructions
4. IMPLEMENT the feature
5. BUILD: bun run build
6. TEST: verify the CLI works
7. UPDATE features.json → set passes: true
8. UPDATE progress.txt → add session notes
9. COMMIT only packages/harness-orchestrator/* changes

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
⚠️  When done with the current feature, type /exit to proceed to next.
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`,
};

/**
 * Harness Dashboard package
 */
const dashboardHarness: HarnessConfig = {
  id: 'harness-dashboard',
  name: 'harness-dashboard',
  icon: '📦',
  description: 'Web dashboard for harness visualization',
  cwd: `${PROJECT_ROOT}/packages/harness-dashboard`,
  featuresPath: `${PROJECT_ROOT}/packages/harness-dashboard/features.json`,
  progressPath: `${PROJECT_ROOT}/packages/harness-dashboard/progress.txt`,
  isolationPrompt: `You are working on the @mms/harness-dashboard package.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🔒 ISOLATION RULES - READ CAREFULLY
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

✅ YOU MAY ONLY MODIFY:
   - packages/harness-dashboard/**/*
   - This includes: src/, features.json, progress.txt, package.json

❌ DO NOT MODIFY:
   - apps/canvas/**/*
   - Root features.json, claude-progress.txt, CLAUDE.md
   - packages/harness-orchestrator/**/*
   - packages/toolkit/**/*

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📋 PACKAGE HARNESS PROTOCOL
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

1. READ packages/harness-dashboard/progress.txt → current state
2. READ packages/harness-dashboard/features.json → find next feature
3. IMPLEMENT the feature
4. TEST: verify the dashboard works
5. UPDATE features.json → set passes: true
6. UPDATE progress.txt → add session notes
7. COMMIT only packages/harness-dashboard/* changes

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
⚠️  When done with the current feature, type /exit to proceed to next.
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`,
};

/**
 * All available harnesses
 */
export const harnesses: HarnessConfig[] = [
  rootHarness,
  orchestratorHarness,
  dashboardHarness,
];

/**
 * Get harness by ID
 */
export function getHarness(id: string): HarnessConfig | undefined {
  return harnesses.find((h) => h.id === id);
}

/**
 * Get pending features count for a harness
 */
export async function getPendingCount(harness: HarnessConfig): Promise<number> {
  try {
    const file = Bun.file(harness.featuresPath);
    const data = await file.json();
    return data.features?.filter((f: { passes?: boolean }) => !f.passes).length ?? 0;
  } catch {
    return 0;
  }
}

/**
 * Get next pending feature for a harness
 */
export async function getNextFeature(
  harness: HarnessConfig
): Promise<{ id: string; description: string } | null> {
  try {
    const file = Bun.file(harness.featuresPath);
    const data = await file.json();
    const next = data.features?.find((f: { passes?: boolean }) => !f.passes);
    return next ? { id: next.id, description: next.description } : null;
  } catch {
    return null;
  }
}

