     1→#!/usr/bin/env bun
     2→/**
     3→ * MMS Harness Runner
     4→ *
     5→ * Automated harness execution with PTY support.
     6→ * - Spawns Claude sessions with proper TTY
     7→ * - Executes features sequentially
     8→ * - Sends macOS notifications on events
     9→ */
    10→
    11→import { spawn } from '@zenyr/bun-pty';
    12→import {
    13→  harnesses,
    14→  getHarness,
    15→  getPendingCount,
    16→  getNextFeature,
    17→  type HarnessConfig,
    18→} from './harness-config';
    19→
    20→// ─────────────────────────────────────────────────────────────────────────────
    21→// COLORS
    22→// ─────────────────────────────────────────────────────────────────────────────
    23→
    24→const colors = {
    25→  reset: '\x1b[0m',
    26→  bold: '\x1b[1m',
    27→  dim: '\x1b[2m',
    28→  red: '\x1b[31m',
    29→  green: '\x1b[32m',
    30→  yellow: '\x1b[33m',
    31→  blue: '\x1b[34m',
    32→  magenta: '\x1b[35m',
    33→  cyan: '\x1b[36m',
    34→};
    35→
    36→function print(msg: string) {
    37→  console.log(msg);
    38→}
    39→
    40→function printHeader(title: string) {
    41→  print(`\n${colors.bold}${colors.blue}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${colors.reset}`);
    42→  print(`${colors.bold}${colors.blue}  ${title}${colors.reset}`);
    43→  print(`${colors.bold}${colors.blue}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${colors.reset}\n`);
    44→}
    45→
    46→function printSuccess(msg: string) {
    47→  print(`${colors.green}✓ ${msg}${colors.reset}`);
    48→}
    49→
    50→function printError(msg: string) {
    51→  print(`${colors.red}✗ ${msg}${colors.reset}`);
    52→}
    53→
    54→function printInfo(msg: string) {
    55→  print(`${colors.blue}ℹ ${msg}${colors.reset}`);
    56→}
    57→
    58→// ─────────────────────────────────────────────────────────────────────────────
    59→// MACOS NOTIFICATIONS
    60→// ─────────────────────────────────────────────────────────────────────────────
    61→
    62→async function notify(title: string, message: string, sound: string = 'Ping') {
    63→  try {
    64→    await Bun.spawn([
    65→      'osascript',
    66→      '-e',
    67→      `display notification "${message}" with title "${title}" sound name "${sound}"`,
    68→    ]).exited;
    69→  } catch (e) {
    70→    // Ignore notification errors
    71→  }
    72→}
    73→
    74→// ─────────────────────────────────────────────────────────────────────────────
    75→// MENU
    76→// ─────────────────────────────────────────────────────────────────────────────
    77→
    78→async function showMenu(): Promise<HarnessConfig | null> {
    79→  printHeader('🔧 MMS Harness Runner');
    80→
    81→  print('Selecione o harness:\n');
    82→
    83→  // Get pending counts for all harnesses
    84→  const counts = await Promise.all(
    85→    harnesses.map(async (h) => ({
    86→      harness: h,
    87→      pending: await getPendingCount(h),
    88→    }))
    89→  );
    90→
    91→  // Display options
    92→  counts.forEach(({ harness, pending }, index) => {
    93→    const pendingText =
    94→      pending > 0 ? `${colors.yellow}${pending} pendentes${colors.reset}` : `${colors.green}✓ completo${colors.reset}`;
    95→    print(`  ${colors.cyan}${index + 1}.${colors.reset} ${harness.icon} ${harness.name} - ${pendingText}`);
    96→  });
    97→
    98→  print(`\n  ${colors.dim}0. Sair${colors.reset}`);
    99→  print('');
   100→
   101→  // Read user input
   102→  process.stdout.write(`${colors.bold}> ${colors.reset}`);
   103→
   104→  const reader = Bun.stdin.stream().getReader();
   105→  const { value } = await reader.read();
   106→  reader.releaseLock();
   107→
   108→  if (!value) return null;
   109→
   110→  const input = new TextDecoder().decode(value).trim();
   111→  const choice = parseInt(input, 10);
   112→
   113→  if (choice === 0 || isNaN(choice)) {
   114→    return null;
   115→  }
   116→
   117→  if (choice < 1 || choice > harnesses.length) {
   118→    printError('Opção inválida');
   119→    return null;
   120→  }
   121→
   122→  return harnesses[choice - 1];
   123→}
   124→
   125→// ─────────────────────────────────────────────────────────────────────────────
   126→// FEATURE EXECUTION
   127→// ─────────────────────────────────────────────────────────────────────────────
   128→
   129→async function executeFeature(
   130→  harness: HarnessConfig,
   131→  featureId: string,
   132→  featureDesc: string,
   133→  current: number,
   134→  total: number
   135→): Promise<boolean> {
   136→  printHeader(`🎯 Tarefa ${current}/${total}: ${featureId}`);
   137→  print(`${colors.dim}${featureDesc}${colors.reset}\n`);
   138→
   139→  return new Promise((resolve) => {
   140→    // Spawn Claude with PTY
   141→    const pty = spawn('claude', ['--append-system-prompt', harness.isolationPrompt], {
   142→      cwd: harness.cwd,
   143→      env: process.env as Record<string, string>,
   144→    });
   145→
   146→    let idleTimeout: ReturnType<typeof setTimeout> | null = null;
   147→    let hasNotifiedIdle = false;
   148→    let outputBuffer = '';
   149→
   150→    // Reset idle timer
   151→    const resetIdleTimer = () => {
   152→      if (idleTimeout) clearTimeout(idleTimeout);
   153→      hasNotifiedIdle = false;
   154→
   155→      idleTimeout = setTimeout(async () => {
   156→        if (!hasNotifiedIdle) {
   157→          hasNotifiedIdle = true;
   158→          await notify('🤖 Harness', `Aguardando input - ${featureId}`, 'Purr');
   159→        }
   160→      }, 30000); // 30 seconds of inactivity
   161→    };
   162→
   163→    // Handle PTY data
   164→    pty.onData((data: string) => {
   165→      process.stdout.write(data);
   166→      outputBuffer += data;
   167→      resetIdleTimer();
   168→
   169→      // Detect patterns
   170→      if (outputBuffer.includes('Do you want to')) {
   171→        // Claude is asking a question
   172→        notify('❓ Harness', `Claude perguntou algo - ${featureId}`, 'Submarine');
   173→      }
   174→    });
   175→
   176→    // Pass stdin to PTY
   177→    const stdinHandler = (chunk: Buffer) => {
   178→      pty.write(chunk.toString());
   179→      resetIdleTimer();
   180→    };
   181→
   182→    process.stdin.on('data', stdinHandler);
   183→    process.stdin.setRawMode?.(true);
   184→
   185→    // Handle PTY exit
   186→    pty.onExit(({ exitCode }) => {
   187→      if (idleTimeout) clearTimeout(idleTimeout);
   188→      process.stdin.removeListener('data', stdinHandler);
   189→      process.stdin.setRawMode?.(false);
   190→
   191→      print(`\n${colors.dim}━━━ Sessão encerrada (código: ${exitCode}) ━━━${colors.reset}\n`);
   192→
   193→      // Check if feature was completed
   194→      resolve(exitCode === 0);
   195→    });
   196→
   197→    resetIdleTimer();
   198→  });
   199→}
   200→
   201→// ─────────────────────────────────────────────────────────────────────────────
   202→// MAIN LOOP
   203→// ─────────────────────────────────────────────────────────────────────────────
   204→
   205→async function runHarness(harness: HarnessConfig) {
   206→  printHeader(`🚀 Iniciando: ${harness.icon} ${harness.name}`);
   207→
   208→  let completedCount = 0;
   209→  let totalPending = await getPendingCount(harness);
   210→
   211→  if (totalPending === 0) {
   212→    printSuccess('Todas as tarefas já foram concluídas!');
   213→    await notify('✅ Harness', `${harness.name}: Nenhuma tarefa pendente`, 'Glass');
   214→    return;
   215→  }
   216→
   217→  printInfo(`${totalPending} tarefas pendentes\n`);
   218→
   219→  while (true) {
   220→    const nextFeature = await getNextFeature(harness);
   221→
   222→    if (!nextFeature) {
   223→      break;
   224→    }
   225→
   226→    const currentNumber = completedCount + 1;
   227→    const success = await executeFeature(
   228→      harness,
   229→      nextFeature.id,
   230→      nextFeature.description,
   231→      currentNumber,
   232→      totalPending
   233→    );
   234→
   235→    if (success) {
   236→      completedCount++;
   237→      printSuccess(`Tarefa ${nextFeature.id} concluída`);
   238→    } else {
   239→      printError(`Tarefa ${nextFeature.id} pode ter falhado`);
   240→    }
   241→
   242→    // Check if there are more features
   243→    const remaining = await getPendingCount(harness);
   244→    if (remaining === 0) {
   245→      break;
   246→    }
   247→
   248→    // Small delay before next task
   249→    await Bun.sleep(1000);
   250→  }
   251→
   252→  // Final notification
   253→  printHeader('📊 Resumo da Sessão');
   254→  printSuccess(`${completedCount} tarefas executadas`);
   255→
   256→  const finalPending = await getPendingCount(harness);
   257→  if (finalPending === 0) {
   258→    printSuccess('Todas as tarefas foram concluídas! 🎉');
   259→    await notify('🎉 Harness Completo', `${harness.name}: Todas as tarefas concluídas!`, 'Glass');
   260→  } else {
   261→    printInfo(`${finalPending} tarefas ainda pendentes`);
   262→    await notify('⏸️ Harness Pausado', `${harness.name}: ${finalPending} tarefas restantes`, 'Basso');
   263→  }
   264→}
   265→
   266→// ─────────────────────────────────────────────────────────────────────────────
   267→// ENTRY POINT
   268→// ─────────────────────────────────────────────────────────────────────────────
   269→
