/**
 * BasicChecker: Programmatic Harness Validation
 *
 * Performs structural validation of a harness project without requiring AI.
 * Checks that all required files exist and have valid content.
 */

import { existsSync, readFileSync, readdirSync, statSync } from 'node:fs';
import { join, resolve } from 'node:path';

export interface CheckResult {
  name: string;
  passed: boolean;
  message: string;
  severity: 'error' | 'warning' | 'info';
  fix?: string;
}

export interface BasicCheckerOptions {
  /** Verbose output */
  verbose?: boolean;
}

export class BasicChecker {
  private projectPath: string;
  private options: BasicCheckerOptions;

  constructor(projectPath: string, options: BasicCheckerOptions = {}) {
    this.projectPath = resolve(projectPath);
    this.options = options;
  }

  /**
   * Run all basic checks and return results
   */
  async runAllChecks(): Promise<CheckResult[]> {
    const results: CheckResult[] = [];

    results.push(this.checkFeaturesJson());
    results.push(this.checkProgressFile());
    results.push(this.checkClaudeMd());
    results.push(this.checkInitSh());
    results.push(this.checkHooksDir());
    results.push(this.checkGitRepo());
    results.push(this.checkHarnessKb());

    return results;
  }

  /**
   * Check if features.json exists and is valid
   */
  checkFeaturesJson(): CheckResult {
    const featuresPath = join(this.projectPath, 'features.json');

    if (!existsSync(featuresPath)) {
      return {
        name: 'features.json',
        passed: false,
        message: 'features.json not found',
        severity: 'error',
        fix: 'Run "harness init" to create a harness structure',
      };
    }

    try {
      const content = readFileSync(featuresPath, 'utf-8');
      const data = JSON.parse(content);

      // Validate required fields
      const errors: string[] = [];

      if (!data.project || typeof data.project !== 'string') {
        errors.push('missing or invalid "project" field');
      }

      if (!Array.isArray(data.features)) {
        errors.push('missing or invalid "features" array');
      } else {
        // Validate each feature
        for (let i = 0; i < data.features.length; i++) {
          const f = data.features[i];
          if (!f.id) errors.push(`feature[${i}] missing "id"`);
          if (!f.description) errors.push(`feature[${i}] missing "description"`);
          if (typeof f.passes !== 'boolean') errors.push(`feature[${i}] missing "passes" boolean`);
          // blockedBy is optional, but if present should be string or array
          if (f.blockedBy !== null && f.blockedBy !== undefined) {
            if (typeof f.blockedBy !== 'string' && !Array.isArray(f.blockedBy)) {
              errors.push(`feature[${i}] "blockedBy" should be string, array, or null`);
            }
          }
        }
      }

      if (errors.length > 0) {
        return {
          name: 'features.json',
          passed: false,
          message: `Invalid structure: ${errors.slice(0, 3).join('; ')}${errors.length > 3 ? ` (+${errors.length - 3} more)` : ''}`,
          severity: 'error',
          fix: 'Fix the structure issues in features.json',
        };
      }

      const completed = data.features.filter((f: { passes: boolean }) => f.passes).length;
      const total = data.features.length;

      return {
        name: 'features.json',
        passed: true,
        message: `Valid with ${total} features (${completed} completed)`,
        severity: 'info',
      };
    } catch (error: any) {
      return {
        name: 'features.json',
        passed: false,
        message: `Invalid JSON: ${error.message}`,
        severity: 'error',
        fix: 'Fix JSON syntax errors in features.json',
      };
    }
  }

  /**
   * Check if progress file exists (claude-progress.txt or progress.txt)
   */
  checkProgressFile(): CheckResult {
    const claudeProgressPath = join(this.projectPath, 'claude-progress.txt');
    const progressPath = join(this.projectPath, 'progress.txt');

    const claudeExists = existsSync(claudeProgressPath);
    const progressExists = existsSync(progressPath);

    if (!claudeExists && !progressExists) {
      return {
        name: 'Progress file',
        passed: false,
        message: 'No progress file found (claude-progress.txt or progress.txt)',
        severity: 'error',
        fix: 'Run "harness init" or "harness session" to create progress file',
      };
    }

    const filePath = claudeExists ? claudeProgressPath : progressPath;
    const fileName = claudeExists ? 'claude-progress.txt' : 'progress.txt';

    try {
      const content = readFileSync(filePath, 'utf-8');

      // Count sessions (## Session N pattern)
      const sessionMatches = content.match(/## Session \d+/g);
      const sessionCount = sessionMatches ? sessionMatches.length : 0;

      if (sessionCount === 0) {
        return {
          name: 'Progress file',
          passed: true,
          message: `${fileName} exists but no sessions logged yet`,
          severity: 'warning',
          fix: 'Add session entries using "harness session"',
        };
      }

      return {
        name: 'Progress file',
        passed: true,
        message: `${fileName} has ${sessionCount} session(s)`,
        severity: 'info',
      };
