      const errors: string[] = [];

      if (!data.project || typeof data.project !== 'string') {
        errors.push('missing or invalid "project" field');
      }

      if (!Array.isArray(data.features)) {
        errors.push('missing or invalid "features" array');
      } else {
        // Validate each feature
        for (let i = 0; i < data.features.length; i++) {
          const f = data.features[i];
          if (!f.id) errors.push(`feature[${i}] missing "id"`);
          if (!f.description) errors.push(`feature[${i}] missing "description"`);
